/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - JSON payload formatting: maps notification payloads to webhook-friendly JSON
 * - Pluggable transport: swap HTTP implementation for testing or custom clients
 * - URL validation: rejects invalid webhook URLs before attempting delivery
 *
 * The adapter conforms to the NotificationAdapter interface and never throws —
 * all errors are captured in the NotificationResult.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

// ---------------------------------------------------------------------------
// Webhook payload types
// ---------------------------------------------------------------------------

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookPayloadBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  recipient: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

/**
 * Represents a webhook delivery request ready for transport.
 */
export interface WebhookRequest {
  url: string;
  headers: Record<string, string>;
  body: WebhookPayloadBody;
  sentAt: Date;
}

// ---------------------------------------------------------------------------
// Webhook transport
// ---------------------------------------------------------------------------

/**
 * Transport interface — abstracts the actual HTTP POST mechanism.
 * Swap implementations for fetch, axios, got, etc.
 */
export interface WebhookTransport {
  post(request: WebhookRequest): Promise<void>;
}

/**
 * In-memory transport that stores sent requests for inspection (testing / dev).
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private sent: WebhookRequest[] = [];

  async post(request: WebhookRequest): Promise<void> {
    this.sent.push(request);
  }

  getSentRequests(): WebhookRequest[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

// ---------------------------------------------------------------------------
// WebhookAdapter
// ---------------------------------------------------------------------------

export interface WebhookAdapterOptions {
  transport?: WebhookTransport;
  headers?: Record<string, string>;
}

const DEFAULT_HEADERS: Record<string, string> = {
  'Content-Type': 'application/json',
};

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private headers: Record<string, string>;

  constructor(options: WebhookAdapterOptions = {}) {
    this.transport = options.transport ?? new InMemoryWebhookTransport();
    this.headers = { ...DEFAULT_HEADERS, ...options.headers };
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate webhook URL
      const url = payload.recipient;
      if (!isValidUrl(url)) {
        this.logger.warn(`Invalid webhook URL: ${url}`);
        return {
          notificationId: payload.id,
          channel: 'webhook',
          success: false,
          error: `Invalid webhook URL: "${url}"`,
          deliveredAt: new Date(),
        };
      }

      // 2. Format the JSON payload
      const body: WebhookPayloadBody = {
        notificationId: payload.id,
        type: payload.type,
        subject: payload.subject,
        body: payload.body,
        recipient: payload.recipient,
        priority: payload.priority,
        createdAt: payload.createdAt.toISOString(),
        metadata: payload.metadata,
      };

      // 3. Build the webhook request
      const request: WebhookRequest = {
        url,
        headers: { ...this.headers },
        body,
        sentAt: new Date(),
      };

      // 4. Send through the transport
      await this.transport.post(request);

      this.logger.info(`Webhook delivered to ${url}: ${payload.subject}`);

      return {
        notificationId: payload.id,
        channel: 'webhook',
        success: true,
        deliveredAt: request.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to deliver webhook to ${payload.recipient}: ${errorMessage}`);

      return {
        notificationId: payload.id,
        channel: 'webhook',
        success: false,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent requests (delegates to transport if it supports inspection). */
  getSentRequests(): WebhookRequest[] {
    if (this.transport instanceof InMemoryWebhookTransport) {
      return this.transport.getSentRequests();
    }
    return [];
  }

  /** Clear sent requests (delegates to transport if it supports it). */
  clearSentRequests(): void {
    if (this.transport instanceof InMemoryWebhookTransport) {
      this.transport.clear();
    }
  }
}

// ---------------------------------------------------------------------------
// Utility
// ---------------------------------------------------------------------------

function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

