import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type {
  WebhookTransport,
  WebhookRequest,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'webhook',
    recipient: 'https://hooks.example.com/notify',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-01-01'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let transport: InMemoryWebhookTransport;
  let adapter: WebhookAdapter;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({ transport });
  });

  describe('channel', () => {
    it('should report channel as webhook', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('send()', () => {
    it('should send a webhook and return a successful result', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should deliver the request through the transport', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const requests = transport.getSentRequests();
      expect(requests).toHaveLength(1);
      expect(requests[0]?.url).toBe('https://hooks.example.com/notify');
      expect(requests[0]?.body.notificationId).toBe('notif-0001');
      expect(requests[0]?.body.type).toBe('order-confirmation');
      expect(requests[0]?.body.subject).toBe('Order Confirmation: order-1');
      expect(requests[0]?.body.body).toContain('Widget x2');
    });

    it('should include default Content-Type header', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const requests = transport.getSentRequests();
      expect(requests[0]?.headers['Content-Type']).toBe('application/json');
    });

    it('should include metadata in the webhook body', async () => {
      const payload = makePayload({
        metadata: { orderId: 'order-1', items: 'Widget x2' },
      });
      await adapter.send(payload);

      const requests = transport.getSentRequests();
      expect(requests[0]?.body.metadata).toEqual({
        orderId: 'order-1',
        items: 'Widget x2',
      });
    });

    it('should serialize createdAt as ISO string in the body', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const requests = transport.getSentRequests();
      expect(requests[0]?.body.createdAt).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should omit metadata from body when not provided', async () => {
      const payload = makePayload();
      delete payload.metadata;
      await adapter.send(payload);

      const requests = transport.getSentRequests();
      expect(requests[0]?.body.metadata).toBeUndefined();
    });
  });

  describe('URL validation', () => {
    it('should accept https URLs', async () => {
      const payload = makePayload({ recipient: 'https://hooks.example.com/webhook' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });

    it('should accept http URLs', async () => {
      const payload = makePayload({ recipient: 'http://localhost:3000/webhook' });
      const result = await adapter.send(payload);
      expect(result.success).toBe(true);
    });

    it('should fail for invalid URLs', async () => {
      const payload = makePayload({ recipient: 'not-a-url' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(transport.getSentRequests()).toHaveLength(0);
    });

    it('should fail for non-http protocols', async () => {
      const payload = makePayload({ recipient: 'ftp://files.example.com/hook' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });
  });

  describe('custom headers', () => {
    it('should merge custom headers with defaults', async () => {
      const customAdapter = new WebhookAdapter({
        transport,
        headers: { 'Authorization': 'Bearer token123' },
      });

      await customAdapter.send(makePayload());

      const requests = transport.getSentRequests();
      expect(requests[0]?.headers['Content-Type']).toBe('application/json');
      expect(requests[0]?.headers['Authorization']).toBe('Bearer token123');
    });

    it('should allow overriding default headers', async () => {
      const customAdapter = new WebhookAdapter({
        transport,
        headers: { 'Content-Type': 'application/json; charset=utf-8' },
      });

      await customAdapter.send(makePayload());

      const requests = transport.getSentRequests();
      expect(requests[0]?.headers['Content-Type']).toBe('application/json; charset=utf-8');
    });
  });

  describe('error handling', () => {
    it('should return a failed result when transport throws', async () => {
      const failingTransport: WebhookTransport = {
        async post() {
          throw new Error('Connection refused');
        },
      };

      const failAdapter = new WebhookAdapter({ transport: failingTransport });
      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(result.notificationId).toBe('notif-0001');
    });

    it('should handle non-Error thrown values', async () => {
      const failingTransport: WebhookTransport = {
        async post() {
          throw 'string error';
        },
      };

      const failAdapter = new WebhookAdapter({ transport: failingTransport });
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('string error');
    });
  });

  describe('getSentRequests / clearSentRequests', () => {
    it('should return sent requests from the in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ id: 'notif-0002', recipient: 'https://other.example.com/hook' }));

      expect(adapter.getSentRequests()).toHaveLength(2);
    });

    it('should clear sent requests', async () => {
      await adapter.send(makePayload());
      adapter.clearSentRequests();

      expect(adapter.getSentRequests()).toHaveLength(0);
    });

    it('should return empty array when transport is not InMemoryWebhookTransport', () => {
      const customTransport: WebhookTransport = { async post() {} };
      const customAdapter = new WebhookAdapter({ transport: customTransport });

      expect(customAdapter.getSentRequests()).toEqual([]);
    });
  });
});

describe('InMemoryWebhookTransport', () => {
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
  });

  it('should store sent requests', async () => {
    const request: WebhookRequest = {
      url: 'https://hooks.example.com/notify',
      headers: { 'Content-Type': 'application/json' },
      body: {
        notificationId: 'notif-0001',
        type: 'order-confirmation',
        subject: 'Test',
        body: 'Test body',
        recipient: 'https://hooks.example.com/notify',
        priority: 'normal',
        createdAt: '2026-01-01T00:00:00.000Z',
      },
      sentAt: new Date(),
    };
    await transport.post(request);

    expect(transport.getSentRequests()).toHaveLength(1);
    expect(transport.getSentRequests()[0]?.url).toBe('https://hooks.example.com/notify');
  });

  it('should clear stored requests', async () => {
    const request: WebhookRequest = {
      url: 'https://hooks.example.com/notify',
      headers: {},
      body: {
        notificationId: 'notif-0001',
        type: 'order-confirmation',
        subject: 'Test',
        body: 'Test body',
        recipient: 'https://hooks.example.com/notify',
        priority: 'normal',
        createdAt: '2026-01-01T00:00:00.000Z',
      },
      sentAt: new Date(),
    };
    await transport.post(request);
    transport.clear();
    expect(transport.getSentRequests()).toHaveLength(0);
  });
});

